class APIResponse:
    @staticmethod
    def success(message="Operation successful", data=None, status_code=200, ...):
        response_data = {
            "status": ResponseStatus.SUCCESS.value,
            "message": message,
        }
        if data is not None:
            response_data["data"] = data
        return Response(response_data, status=status_code)

